{
  "customer_summary": {
    "summary": "The front‑end of the application is being upgraded to Angular 19. Angular 19 removes the old SASS import mechanism and requires the new Angular Builder ( @angular-devkit/build-angular:application ) to compile SASS. Without this migration the application will no longer build after the framework upgrade, which would block any further releases and could expose users to missing UI fixes. The migration therefore ensures the UI can continue to be built, deployed and maintained safely.",
    "impact_level": "medium",
    "is_bug": false,
    "workaround": "",
    "eta_category": "short"
  },
  "developer_context": {
    "big_picture": "This repository contains the single‑page Angular front‑end that is used by internal employees and external partners to interact with the Bnotk platform. It lives in the *presentation* layer of a five‑container system (frontend, backend, integration, infra, data). The UI is built with Angular 18‑LTS, Webpack, Karma and Playwright. The task is to migrate the SASS compilation step to the new Angular Builder that Angular 19 mandates. Doing the migration now is required because the upcoming Angular 19 release will break the current build pipeline; postponing it would halt future releases and could introduce UI regressions.",
    "scope_boundary": "IN: Update the Angular build configuration (angular.json) to use @angular-devkit/build-angular:application, adjust any SASS import statements according to the ADR, run the full unit‑test (Karma) and end‑to‑end (Playwright) suites, and verify the CI/CD Gradle scripts that invoke the Angular build. OUT: Any backend Java services, domain logic, database schema, or unrelated UI components that do not touch SASS or the build pipeline.",
    "classification_assessment": "",
    "classification_confidence": -1,
    "affected_components": [
      "Angular Build Configuration (infrastructure layer)",
      "SASS Stylesheets (presentation layer)"
    ],
    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 drops support for the legacy SASS compiler; the new @angular-devkit/build-angular:application builder must be used or the project will fail to compile.",
        "severity": "blocking",
        "source_facts": [
          "tech_versions.json: Angular 18‑lts",
          "ADR: https://wiki.bnotk.de/spaces/UVZUSLNAS/pages/386958007/UVZ-09-ADR-003+-+Frontend+Build+Strategy+SASS+Import+Deprecation"
        ]
      },
      {
        "category": "dependency_risk",
        "boundary": "The new builder brings updated peer dependencies (sass, postcss, etc.). Compatibility with the currently pinned versions must be verified to avoid runtime build errors.",
        "severity": "caution",
        "source_facts": [
          "dependencies.json: @angular/* v18‑lts (will be upgraded to 19)",
          "tech_versions.json: TypeScript 4.9.5"
        ]
      },
      {
        "category": "pattern_constraint",
        "boundary": "The ADR documents a deprecation of the old SASS import syntax. All style files may need to be refactored to the new import style before the builder can process them.",
        "severity": "blocking",
        "source_facts": [
          "ADR: https://wiki.bnotk.de/spaces/UVZUSLNAS/pages/386958007/UVZ-09-ADR-003+-+Frontend+Build+Strategy+SASS+Import+Deprecation"
        ]
      },
      {
        "category": "testing_constraint",
        "boundary": "Because the compiler change can affect CSS output, the full test suite (Karma unit tests and Playwright e2e tests) must be executed to catch regressions in layout or theming.",
        "severity": "caution",
        "source_facts": [
          "Issue description: \"additional testing may be necessary to minimize the risk of potential regressions\""
        ]
      },
      {
        "category": "infrastructure_constraint",
        "boundary": "The CI pipeline uses Gradle 8.2.1 to trigger the Angular build. Build scripts may need to be updated to pass the new builder options.",
        "severity": "info",
        "source_facts": [
          "tech_versions.json: Gradle 8.2.1"
        ]
      }
    ],
    "architecture_notes": "The front‑end lives in the **frontend container** (one of the five containers). Within that container the **presentation layer** holds all Angular components, stylesheets and the build configuration. The SASS compiler is part of the **infrastructure sub‑layer** that supports the build process. The component to touch is the **Angular Build Configurator** (angular.json) which is consumed by the **CI/CD pipeline** (Gradle scripts). Neighbouring components are the **Webpack bundler**, **Karma unit‑test runner**, and **Playwright e2e runner** – all of which read the compiled CSS output. Changing the builder therefore ripples to those neighbours but does not affect backend services or domain logic.",
    "anticipated_questions": [
      {
        "question": "Do I need to change any npm packages besides the builder?",
        "answer": "Only the builder package (@angular-devkit/build-angular) is required, but you should verify that the versions of @angular/*, sass, and postcss that are pulled in as peer dependencies are compatible with the rest of the stack."
      },
      {
        "question": "Will the existing SASS files compile without changes?",
        "answer": "The ADR indicates that the old import syntax is deprecated. Some files may need to be updated to the new import style before the new builder can process them."
      },
      {
        "question": "Is the CI pipeline affected?",
        "answer": "Yes. The Gradle task that runs `ng build` will need to reference the new builder configuration. Verify the Gradle script after the migration."
      },
      {
        "question": "How extensive should the testing be?",
        "answer": "Run the full Karma unit‑test suite and the Playwright end‑to‑end tests. Pay special attention to visual regressions or layout changes caused by CSS output differences."
      },
      {
        "question": "What is the fallback if the migration fails?",
        "answer": "Continuing with the old builder is not an option after Angular 19 is released, because the framework will reject the deprecated SASS compilation path. A temporary fix would be to stay on Angular 18, but that defeats the purpose of the planned upgrade."
      }
    ],
    "linked_tasks": [
      "UVZ-09-ADR-003 (Frontend Build Strategy SASS Import Deprecation)",
      "Angular 19 upgrade epic (if any)"
    ]
  }
}

