    "context_boundaries": [
      {
        "category": "technology_constraint",
        "boundary": "Angular 19 requires TypeScript ≥5.0 and Node.js ≥18. The current stack uses TypeScript 4.9.5 and an unspecified older Node version, so both must be upgraded before the framework can be upgraded.",
        "severity": "blocking",
        "source_facts": [
          "tech_versions.json: TypeScript 4.9.5",
          "tech_versions.json: Angular 18‑lts",
          "issue description: node.js listed as a required dependency"
        ]
      },
      {
        "category": "dependency_risk",
        "boundary": "The custom ng‑bootstrap patch referenced in the acceptance criteria may not be compatible with Angular 19; compatibility must be verified and the patch reapplied if needed.",
        "severity": "caution",
        "source_facts": [
          "issue acceptance criteria: ng-bootstrap (Patch von UVZUSLNVV‑5824 muss berücksichtigt werden)"
        ]
      },
      {
        "category": "dependency_risk",
        "boundary": "ag‑grid‑angular and ag‑grid‑community versions used for Angular 18 may have breaking changes in their Angular 19 compatible releases; these libraries need to be upgraded and tested.",
        "severity": "caution",
        "source_facts": [
          "issue acceptance criteria: ag-grid-angular, ag-grid-community"
        ]
      },
      {
        "category": "pattern_library_dependency",
        "boundary": "bnotk/ds‑ng version 12.6.0 is built for Angular 19; all UI components that rely on the pattern library must be compiled against the new version.",
        "severity": "info",
        "source_facts": [
          "issue acceptance criteria: bnotk/ds‑ng"
        ]
      },
      {
        "category": "deprecation",
        "boundary": "The vertical action bar is deprecated but still supported until Pattern Library 13.2.0; after the upgrade it must continue to work, but future removal should be planned.",
        "severity": "info",
        "source_facts": [
          "issue acceptance criteria: Vertical action bar is still used (deprecated but still possible to use till PL 13.2.0)"
        ]
      },
      {
        "category": "security_boundary",
        "boundary": "Angular 18 security support ends 21 Nov 2025; staying on this version would leave the portal without critical security patches.",
        "severity": "blocking",
        "source_facts": [
          "issue description: support for security updates ended on 21.11.2025 for Angular 18"
        ]
      }
    ],
    "architecture_notes": "The UVZ system consists of five containers. The front‑end Angular application lives in the **\"frontend\" container** and occupies the **presentation layer** (≈287 components). It consumes services from the **application layer** (≈184 components) via HTTP/REST. The Pattern Library (bnotk/ds‑ng) is a shared UI component library also part of the presentation layer and is imported by many UI components, including the vertical action bar. The build pipeline (Webpack 5, Angular CLI) resides in the infrastructure layer of the same container. Upgrading Angular therefore touches: • The Angular core packages in the presentation layer, • The Pattern Library package, • Build tooling (Angular CLI, Webpack), • Node/TypeScript versions used by the infrastructure layer, and • All UI components that depend on the upgraded libraries. Neighboring components include the authentication guard (uses DefaultExceptionHandler), data‑grid components (ag‑grid), and UI widgets (ng‑bootstrap, ng‑select). No backend Java components are directly affected.",
    "anticipated_questions": [
      {
        "question": "Which Node.js and TypeScript versions are required for Angular 19?",
        "answer": "Angular 19 officially supports Node.js 18 LTS (or newer) and TypeScript 5.0+. The current project uses TypeScript 4.9.5, so both Node and TypeScript must be upgraded before the Angular upgrade can succeed."
      },
      {
        "question": "Are there breaking API changes in Angular 19 that will affect our existing code?",
        "answer": "Angular 19 introduces several deprecations and removal of legacy APIs (e.g., ViewEngine is fully removed, some router APIs changed). All components that use deprecated APIs will need to be refactored; the vertical action bar, being deprecated, should be checked for any removed hooks."
      },
      {
        "question": "Will the custom ng‑bootstrap patch still apply after moving to Angular 19?",
        "answer": "The patch was created for Angular 18. Compatibility must be verified against the Angular 19 version of ng‑bootstrap; if the patch does not apply cleanly, it will need to be re‑implemented for the newer version."
      },
      {
        "question": "Do we need to adjust the CI/CD pipeline (e.g., Angular CLI version, Docker images)?",
        "answer": "Yes. The pipeline currently uses Angular CLI 18‑lts and a Node image compatible with that version. Both the CLI and the base Node image must be updated to the versions required by Angular 19."
      },
      {
        "question": "Is the vertical action bar guaranteed to keep working after the upgrade?",
        "answer": "The action bar is deprecated but still supported up to Pattern Library 13.2.0, so it should continue to work with PL 12.6.0. Nevertheless, functional tests should verify its behavior after the upgrade."
      }
    ],
    "linked_tasks": [
      "UVZUSLNVV-5824 (this upgrade ticket)",
      "BNUVZ-12529 (analysis comment \"how to get to angular 21\")"
    ]
  }
}

